func HashedPeerID(s string) (PeerID, error) {
	var p PeerID
	if s == "" {
		return p, errors.New("cannot generate peer id from empty string")
	}
	h := sha1.New()
	io.WriteString(h, s)
	copy(p[:], h.Sum(nil))
	return p, nil
}

func decryptPEMBlock(data, secret []byte) ([]byte, error) {
	block, _ := pem.Decode(data)
	if block == nil || len(block.Bytes) < 1 {
		return nil, errors.New("empty block")
	}
	decoded, err := x509.DecryptPEMBlock(block, secret)
	if err != nil {
		return nil, fmt.Errorf("decrypt block: %s", err)
	}
	return decoded, nil
}
